#!/bin/bash
# Run from your project root: bash add_new_cards_3.sh
# This script:
# 1. Deduplicates against existing slugs in cardData.ts (case-insensitive)
# 2. Fixes duplicate set names (EX vs ex capitalisation)
# 3. Appends only truly new cards

node << 'NODESCRIPT'
const fs = require('fs');
const file = 'lib/cardData.ts';
let src = fs.readFileSync(file, 'utf8');

// Fix set name duplicates caused by capitalisation differences
// Keep the ones already in the file, normalize incoming ones to match
const setNameFixes = {
  'Mega Dream EX': 'MEGA Dream ex',    // incoming uses 'MEGA Dream ex'
  'Terastal Festival EX': 'Terastal Festival ex',
  'Shiny Treasure EX': 'Shiny Treasure ex',
  'Terastal Festival Ex': 'Terastal Festival ex',
};

// Extract all existing slugs (case-insensitive key)
const existingSlugs = new Set(
  [...src.matchAll(/slug: '([^']+)'/g)].map(m => m[1].toLowerCase())
);

console.log(`Existing cards: ${existingSlugs.size}`);

