const toAdd = newCards.filter(line => {
  const slugMatch = line.match(/slug: '([^']+)'/);
  if (!slugMatch) return false;
  return !existingSlugs.has(slugMatch[1].toLowerCase());
});

console.log(`New cards to add: ${toAdd.length} (skipped ${newCards.length - toAdd.length} duplicates)`);

if (toAdd.length === 0) {
  console.log('Nothing to add!');
  process.exit(0);
}

// Remove closing ]; and append
src = src.replace(/\];\s*$/, '');
src += '\n' + toAdd.join('\n') + '\n];\n';
fs.writeFileSync(file, src);
console.log('✅ Done!');
